+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle?: ListStyle = 'bullet';
+  bulletMarker?: string = '-';
+  orderedListStyle?: OrderedListStyle = 'always-one';
+  indentSize?: number = 2;
+  minLevel?: number = 2;
+  maxLevel?: number = 6;
+  title?: string = '';
+  useExplicitIds?: boolean = false;
+  stripFormattingInToc?: boolean = false;
+  excludeHeadings?: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const tocStartRegex = /<!--\\s*toc\\s*-->/gi;
+const tocEndRegex = /<!--\\s*\\/toc\\s*-->/gi;
+const atxHeadingRegex = /^(?: {0,3})(#{1,6})[ \	]+(.*?)[ \	]*$/;
+
+function resolveLinksAndRemoveImages(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|\
]+)(?:\\|([^\\]|\
]+))?(?:\\|[^\\]\
]+)?\\]\\]/g, (_match, target: string, display?: string) => display ?? target)
+      .replace(/\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replace(/<[^>]*>/g, '')
+      .replace(/(\\*\\*|__|~~|`)/g, '')
+      .replace(/\\\\([!"#$%&'()*+,\\-./:;<=>?@[\\]^_`{|}~])/g, '$1')
+      .replace(/(^|\\s)[*_]+|[*_]+(?=\\s|$)/g, '$1');
+}
+
+function headingTextAndExplicitId(rawText: string, useExplicitIds: boolean): {text: string, explicitId?: string} {
+  let text = rawText.replace(/[ \	]+#+[ \	]*$/, '');
+  if (!useExplicitIds) {
+    return {text};
+  }
+
+  const explicitId = text.match(/[ \	]*\\{#([^\\s}]+)\\}[ \	]*$/);
+  if (explicitId) {
+    text = text.slice(0, explicitId.index).trimEnd();
+    return {text, explicitId: explicitId[1]};
+  }
+
+  return {text};
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(resolveLinksAndRemoveImages(text))
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9\\-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-|-$/g, '');
+}
+
+function matchesExcludedHeading(text: string, patterns: string[]): boolean {
+  return patterns.some((pattern) => {
+    const regexMatch = pattern.match(/^\\/(.*)\\/$/);
+    if (regexMatch) {
+      try {
+        return new RegExp(regexMatch[1], 'i').test(text);
+      } catch (_error) {
+        // Treat malformed regular expressions as literal values.
+      }
+    }
+    return pattern.toLocaleLowerCase() === text.toLocaleLowerCase();
+  });
+}
+
+function getHeadings(text: string, options: AutoTocOptions, tocStart: number, tocEnd: number): Heading[] {
+  const headings: Heading[] = [];
+  const anchors = new Set<string>();
+  let inYaml = false;
+  let inCodeFence: {marker: string, length: number} | undefined;
+  let inMath = false;
+  let offset = 0;
+
+  for (const match of text.matchAll(/[^\\r\
]*(?:\\r\
|\
|$)/g)) {
+    const fullLine = match[0];
+    if (fullLine === '') break;
+    const line = fullLine.replace(/\\r?\
$/, '');
+    const lineStart = offset;
+    offset += fullLine.length;
+
+    if (lineStart === 0 && /^---[ \	]*$/.test(line)) {
+      inYaml = true;
+      continue;
+    }
+    if (inYaml) {
+      if (/^(?:---|\\.\\.\\.)[ \	]*$/.test(line)) inYaml = false;
+      continue;
+    }
+
+    if (inCodeFence) {
+      const closingFence = new RegExp(`^ {0,3}${inCodeFence.marker}{${inCodeFence.length},}[ \\\	]*$`);
+      if (closingFence.test(line)) inCodeFence = undefined;
+      continue;
+    }
+    const openingFence = line.match(/^ {0,3}(`{3,}|~{3,})/);
+    if (openingFence) {
+      inCodeFence = {marker: openingFence[1][0], length: openingFence[1].length};
+      continue;
+    }
+
+    if (/^[ \	]*\\$\\$[ \	]*$/.test(line)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath || (lineStart >= tocStart && lineStart < tocEnd)) continue;
+
+    const headingMatch = line.match(atxHeadingRegex);
+    if (!headingMatch) continue;
+    const level = headingMatch[1].length;
+    if (level < options.minLevel || level > options.maxLevel) continue;
+
+    const parsed = headingTextAndExplicitId(headingMatch[2], options.useExplicitIds);
+    const displayText = resolveLinksAndRemoveImages(parsed.text);
+    const comparableText = stripFormatting(displayText);
+    if (matchesExcludedHeading(comparableText, options.excludeHeadings)) continue;
+
+    const baseAnchor = parsed.explicitId ?? makeAnchor(parsed.text);
+    let anchor = baseAnchor;
+    let duplicate = 1;
+    while (anchors.has(anchor)) anchor = `${baseAnchor}-${duplicate++}`;
+    anchors.add(anchor);
+
+    headings.push({
+      level,
+      text: options.stripFormattingInToc ? comparableText : displayText,
+      anchor,
+    });
+  }
+
+  return headings;
+}
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    tocStartRegex.lastIndex = 0;
+    const start = tocStartRegex.exec(text);
+    if (!start || start.index === undefined) return text;
+
+    tocEndRegex.lastIndex = start.index + start[0].length;
+    const end = tocEndRegex.exec(text);
+    const endIndex = end?.index ?? start.index + start[0].length;
+    const headings = getHeadings(text, options, start.index, endIndex);
+    const tocLines = headings.map((heading, index) => {
+      const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'number' ? (options.orderedListStyle === 'increment' ? `${index + 1}.` : '1.') : options.bulletMarker;
+      return `${indentation}${marker} [${heading.text}](#${heading.anchor})`;
+    });
+    const regionLines = [start[0], ''];
+    if (options.title !== '') regionLines.push(options.title, '');
+    regionLines.push(...tocLines, '', end?.[0] ?? '<!-- /toc -->');
+
+    const prefix = text.slice(0, start.index);
+    const suffixStart = end ? end.index + end[0].length : start.index + start[0].length;
+    const suffix = text.slice(suffixStart).replace(/^(?:[ \	]*\\r?\
)+/, '');
+    return `${prefix}${regionLines.join('\
')}\
\
${suffix}`;
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Use bullet list items.'}, {value: 'number', description: 'Use ordered list items.'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Use 1. for every item.'}, {value: 'increment', description: 'Increment every item.'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
